import json
from google import genai

class AIService:
    def __init__(self, project_id: str = None, location: str = "us-central1"):
        self.project_id = project_id
        self.location = location
        try:
            self.client = genai.Client(api_key="AIzaSyB43_2R4-9Ros7VI9zbvVngXMgP75zP4UY")
        except Exception as e:
            print(f"Warning: Failed to initialize AI Studio: {e}")
            self.client = None

    def analyze_qualitative(self, company_name: str, profile: dict, metrics: dict) -> dict:
        """
        Prompts Gemini to generate the qualitative JSON structures defined in the technical design.
        """
        if not self.client:
            return {"error": "AI Studio not initialized."}

        prompt = f"""
        You are an expert financial analyst and professional value investor.
        Analyze the company: {company_name}.
        Profile Data: {json.dumps(profile)}
        Metrics Data: {json.dumps(metrics)}

        Please conduct an exceptionally thorough, deep-dive qualitative analysis of the company, focusing specifically on their growth strategy, competitive moats, and operational/strategic challenges, integrating highly specific insights from their recent 10-K filings. Avoid generic high-level summaries; provide rich, professional-grade equity research paragraphs.

        Using your internal knowledge of the NAICS (North American Industry Classification System) taxonomy, classify the company into its most accurate Sector (2-digit level), Subsector (3-digit level), and Industry Group (4-digit level).

        Please provide a detailed qualitative analysis in JSON format exactly matching this structure:
        {{
            "overview": "A comprehensive, multi-paragraph overview of the company's business model, operations, and general context.",
            "sector": "Exact Title of the NAICS Sector",
            "subsector": "Exact Title of the NAICS Subsector",
            "industry_group": "Exact Title of the NAICS Industry Group",
            "sources": {{ "source_links": ["list of 2-3 relevant 10-K or news links"] }},
            "growth_plans": {{ 
                "strategy_summary": "An exceptionally thorough, multi-paragraph value-investing analysis of the company's long-term organic and inorganic growth vectors. Integrate highly specific details from the company's recent 10-K, including target markets, technology platforms, Capex priorities, and strategic product lines (e.g. AI chips, cloud services, subscription ecosystems, hardware iterations).", 
                "key_initiatives": [
                    "A highly specific key initiative from the 10-K detailing R&D directions, production capacity expansion, infrastructure upgrades, or new market/geographic entries.",
                    "Another highly detailed key initiative from the 10-K showing exactly how capital is allocated for future growth."
                ] 
            }},
            "competitors": {{ "competitor_list": [ {{"name": "...", "competition_scope": "..."}} ] }},
            "risks": {{ 
                "key_risks": [ 
                    {{"risk": "Highly specific operational/regulatory risk", "explanation": "A thorough, detailed explanation of how this risk affects cash flows, margins, or terminal value based on the 10-K Item 1A Risk Factors."}},
                    {{"risk": "Competitive or macroeconomic threat", "explanation": "A thorough, detailed explanation of this challenge based on the 10-K."}}
                ] 
            }},
            "moats": {{
                "moat_types": [ 
                    {{"type": "Moat Category (e.g. Switching Costs, Network Effects, Cost Advantage, Intangible Assets)", "strength": "Wide or Narrow", "rationale": "A deep, thorough value-investor's explanation of how this moat works, its durability, how it presents itself in the company's return metrics (ROIC/ROE), and specific barriers to entry for competitors."}}
                ],
                "competitor_comparison": "An extremely detailed, comparative analysis of competitive dynamics, detailing specific unit economics, pricing power, distribution channels, and market shares relative to key competitors."
            }},
            "management": {{
                "ceo_tenure_years": 0,
                "ceo_employee_rating": 0.0,
                "employee_happiness_score": 0.0,
                "board_of_directors_summary": "A thorough description of board oversight, independence, and alignment with shareholders."
            }},
            "market_and_bias": {{
                "gurus_buying": ["..."],
                "bias_checklist": [
                    {{"question": "Are we outside the circle of competence?", "answer": false, "rationale": "..."}},
                    {{"question": "Is the industry declining?", "answer": false, "rationale": "..."}},
                    {{"question": "Are the Big 4 numbers failing to grow or slowing down?", "answer": false, "rationale": "..."}},
                    {{"question": "Is debt increasing (or > 2 years FCF)?", "answer": false, "rationale": "..."}},
                    {{"question": "Is EPS engineered by buybacks?", "answer": false, "rationale": "..."}},
                    {{"question": "Is demand for the product uncertain in 10 years?", "answer": false, "rationale": "..."}},
                    {{"question": "Was the CEO recently replaced?", "answer": false, "rationale": "..."}},
                    {{"question": "Is there an unfriendly union?", "answer": false, "rationale": "..."}},
                    {{"question": "Have the 10-K footnotes been read?", "answer": true, "rationale": "..."}},
                    {{"question": "Is there an event that may permanently damage the business?", "answer": false, "rationale": "..."}}
                ]
            }}
        }}

        Return ONLY the raw JSON object. Do not include markdown code blocks.
        """

        try:
            response = self.client.models.generate_content(
                model="gemini-3.1-pro-preview",
                contents=prompt
            )
            text = response.text.strip()
            if text.startswith("```json"):
                text = text[7:]
            if text.endswith("```"):
                text = text[:-3]
            return json.loads(text)
        except Exception as e:
            print(f"AI Studio Generation Failed: {e}.")
            return {"error": f"AI Studio Generation Failed: {e}"}

import statistics
from typing import Dict, Any, List

class FinancialCalculator:
    def __init__(self):
        self.marr = 0.15

    def calculate_cagr(self, start_val: float, end_val: float, years: int) -> float:
        if start_val <= 0 or years <= 0:
            return 0.0
        return (end_val / start_val) ** (1 / years) - 1

    def calculate_growth_rates(self, history: List[Dict[str, Any]]) -> Dict[str, float]:
        """Calculates 1, 3, 5, 10 yr growth rates given a list of historical values sorted by year."""
        if not history or len(history) < 2:
            return {"1_yr": 0.0, "3_yr": 0.0, "5_yr": 0.0, "10_yr": 0.0}

        current = history[-1]["value"]
        rates = {"1_yr": 0.0, "3_yr": 0.0, "5_yr": 0.0, "10_yr": 0.0}

        def safe_cagr(years_back, key):
            if len(history) > years_back:
                start = history[-(years_back + 1)]["value"]
                rates[key] = self.calculate_cagr(start, current, years_back)

        safe_cagr(1, "1_yr")
        safe_cagr(3, "3_yr")
        safe_cagr(5, "5_yr")
        safe_cagr(10, "10_yr")
        return rates

    def calculate_averages(self, history: List[Dict[str, Any]]) -> Dict[str, float]:
        """Calculates 3, 5, 10 yr simple averages given a list of historical values sorted by year (oldest to newest)."""
        if not history:
            return {"3_yr": 0.0, "5_yr": 0.0, "10_yr": 0.0}

        rates = {"3_yr": 0.0, "5_yr": 0.0, "10_yr": 0.0}

        # Determine the key for the value (could be 'v' from metrics.json or 'value' from extracted history)
        val_key = "v" if "v" in history[0] else "value"

        def safe_avg(years_back, key):
            # Take up to `years_back` most recent records
            subset = history[-years_back:] if len(history) >= years_back else history
            vals = [x.get(val_key, 0.0) for x in subset]
            if vals:
                rates[key] = sum(vals) / len(vals)

        safe_avg(3, "3_yr")
        safe_avg(5, "5_yr")
        safe_avg(10, "10_yr")
        return rates

    def calculate_windage_growth_rate(self, fcf_history: List[Dict[str, Any]]) -> tuple[float, str, Dict[str, Any]]:
        """Average of 10-year FCF growth rates within 1 std dev."""
        if len(fcf_history) < 2:
            empty_details = {
                "steps": [],
                "stats": {"mean": 0.0, "stdev": 0.0, "lower_bound": 0.0, "upper_bound": 0.0, "is_filtered": False},
                "final_rate": 0.0
            }
            return 0.0, "Not enough FCF history.", empty_details

        yoy_rates_detailed = []
        for i in range(1, len(fcf_history)):
            prev_year = fcf_history[i-1]["year"]
            curr_year = fcf_history[i]["year"]
            prev = fcf_history[i-1]["value"]
            curr = fcf_history[i]["value"]
            if prev > 0:
                yoy_rates_detailed.append({
                    "from_year": prev_year,
                    "to_year": curr_year,
                    "prev_value": prev,
                    "curr_value": curr,
                    "rate": (curr - prev) / prev
                })

        yoy_rates = [x["rate"] for x in yoy_rates_detailed]

        if not yoy_rates:
            empty_details = {
                "steps": [],
                "stats": {"mean": 0.0, "stdev": 0.0, "lower_bound": 0.0, "upper_bound": 0.0, "is_filtered": False},
                "final_rate": 0.0
            }
            return 0.0, "No valid FCF growth rates.", empty_details

        if len(yoy_rates) < 3:
            mean = statistics.mean(yoy_rates)
            rationale = f"Calculated simple average due to limited data: {mean:.2%}"
            steps = [
                {
                    "from_year": x["from_year"],
                    "to_year": x["to_year"],
                    "prev_value": x["prev_value"],
                    "curr_value": x["curr_value"],
                    "rate": x["rate"],
                    "is_included": True
                }
                for x in yoy_rates_detailed
            ]
            details = {
                "steps": steps,
                "stats": {
                    "mean": mean,
                    "stdev": 0.0,
                    "lower_bound": mean,
                    "upper_bound": mean,
                    "is_filtered": False
                },
                "final_rate": mean
            }
            return mean, rationale, details

        mean = statistics.mean(yoy_rates)
        stdev = statistics.stdev(yoy_rates)
        lower_bound = mean - stdev
        upper_bound = mean + stdev

        valid_rates = [r for r in yoy_rates if lower_bound <= r <= upper_bound]
        windage_gr = statistics.mean(valid_rates) if valid_rates else mean

        steps = [
            {
                "from_year": x["from_year"],
                "to_year": x["to_year"],
                "prev_value": x["prev_value"],
                "curr_value": x["curr_value"],
                "rate": x["rate"],
                "is_included": lower_bound <= x["rate"] <= upper_bound
            }
            for x in yoy_rates_detailed
        ]

        details = {
            "steps": steps,
            "stats": {
                "mean": mean,
                "stdev": stdev,
                "lower_bound": lower_bound,
                "upper_bound": upper_bound,
                "is_filtered": True
            },
            "final_rate": windage_gr
        }

        rationale = f"Average of 10-year FCF growth rates within 1 standard deviation. Raw rates: {[round(r, 2) for r in yoy_rates]}. Valid average: {windage_gr:.2%}"
        return windage_gr, rationale, details

    def calculate_10_cap(self, net_income: float, da: float, capex: float, market_cap: float) -> tuple[float, float, str]:
        """Method A: 10-Cap Owner Earnings"""
        # capex is usually negative in cash flow statements, so we add it if negative, subtract if positive
        # Actually standard formula: Net Income + D&A - Maintenance CapEx
        capex_val = abs(capex) if capex else 0.0
        owner_earnings = net_income + da - capex_val

        if owner_earnings <= 0:
            return owner_earnings, 0.0, "Owner earnings are zero or negative."

        cap_rate = market_cap / owner_earnings
        rationale = f"Owner Earnings = Net Income ({net_income}) + D&A ({da}) - CapEx ({capex_val}) = {owner_earnings}. Cap Rate = Owner Earnings / Market Cap = {cap_rate:.2f}."
        return owner_earnings, cap_rate, rationale

    def calculate_payback_time(self, current_fcf: float, windage_gr: float, market_cap: float) -> tuple[int, List[Dict[str, float]], str]:
        """Method B: Payback Time (FCF)"""
        if current_fcf <= 0:
            return 0, [], "Current FCF is zero or negative."

        projected_fcf = []
        accumulated_fcf = 0.0
        payback_years = 0

        for year in range(1, 11):
            fcf = current_fcf * ((1 + windage_gr) ** year)
            projected_fcf.append({"year": year, "fcf": fcf})
            accumulated_fcf += fcf

            if accumulated_fcf >= market_cap and payback_years == 0:
                payback_years = year

        if payback_years == 0:
            rationale = "Accumulated FCF over 10 years does not reach Market Cap."
        else:
            rationale = f"Accumulated projected FCF reaches Market Cap by Year {payback_years}."

        return payback_years, projected_fcf, rationale

    def calculate_margin_of_safety(self, current_eps: float, windage_gr: float, windage_pe: float) -> tuple[float, Dict[str, str]]:
        """Method C: Margin of Safety (Sticker Price)"""
        step_1_future_eps = current_eps * ((1 + windage_gr) ** 10)
        step_2_future_price = step_1_future_eps * windage_pe
        step_3_sticker_price = step_2_future_price / ((1 + self.marr) ** 10)
        mos_price = step_3_sticker_price / 2

        details = {
            "step_1_future_eps": f"Current EPS ({current_eps:.2f}) * (1 + Windage Growth ({windage_gr:.2%}))^10 = Future EPS ({step_1_future_eps:.2f})",
            "step_2_future_price": f"Future EPS ({step_1_future_eps:.2f}) * Windage PE ({windage_pe:.2f}) = Future Price ({step_2_future_price:.2f})",
            "step_3_sticker_price": f"Future Price ({step_2_future_price:.2f}) / (1 + MARR ({self.marr}))^10 = Sticker Price ({step_3_sticker_price:.2f})",
            "step_4_mos_price": f"Sticker Price ({step_3_sticker_price:.2f}) / 2 = MOS Buy Price ({mos_price:.2f})"
        }

        return mos_price, details

from google.cloud import firestore
from datetime import datetime
import pytz

class DBService:
    def __init__(self, project_id: str):
        self.project_id = project_id
        try:
            self.db = firestore.Client(project=self.project_id)
        except Exception as e:
            print(f"Warning: Failed to initialize Firestore: {e}")
            self.db = None

    def get_company_data(self, ticker: str) -> dict:
        if not self.db:
            return {}

        try:
            company_ref = self.db.collection('companies').document(ticker)
            doc = company_ref.get()
            if not doc.exists:
                return {}

            data = doc.to_dict()
        except Exception as e:
            print(f"Firestore get failed: {e}")
            return {}

        # Get subcollections
        financials = {}
        for fin_doc in company_ref.collection('financials').stream():
            financials[fin_doc.id] = fin_doc.to_dict()
        if financials:
            data['financials'] = financials

        qualitative = {}
        for qual_doc in company_ref.collection('qualitative').stream():
            qualitative[qual_doc.id] = qual_doc.to_dict()
        if qualitative:
            data['qualitative'] = qualitative

        context = {}
        for ctx_doc in company_ref.collection('context').stream():
            context[ctx_doc.id] = ctx_doc.to_dict()
        if context:
            data['context'] = context

        return data

    def save_company_data(self, ticker: str, data: dict):
        if not self.db:
            return

        try:
            company_ref = self.db.collection('companies').document(ticker)

            # Save root data
            root_data = {k: v for k, v in data.items() if k not in ['financials', 'qualitative', 'context']}
            root_data['last_updated'] = datetime.now(pytz.utc).isoformat()
            company_ref.set(root_data)
        except Exception as e:
            print(f"Firestore save failed: {e}")
            return

        # Save financials
        if 'financials' in data:
            for doc_id, doc_data in data['financials'].items():
                doc_data['timestamp'] = datetime.now(pytz.utc).isoformat()
                company_ref.collection('financials').document(doc_id).set(doc_data)

        # Save qualitative
        if 'qualitative' in data:
            for doc_id, doc_data in data['qualitative'].items():
                company_ref.collection('qualitative').document(doc_id).set(doc_data)

        # Save context
        if 'context' in data:
            for doc_id, doc_data in data['context'].items():
                company_ref.collection('context').document(doc_id).set(doc_data)

    def get_batch(self, batch_id: str) -> dict:
        if not self.db:
            return {}
        try:
            doc = self.db.collection('ingestion_batches').document(batch_id).get()
            if doc.exists:
                return doc.to_dict()
        except Exception as e:
            print(f"Firestore get batch failed: {e}")
        return {}

    def save_batch(self, batch_id: str, data: dict):
        if not self.db:
            return
        try:
            self.db.collection('ingestion_batches').document(batch_id).set(data)
        except Exception as e:
            print(f"Firestore save batch failed: {e}")

import requests
from typing import Dict, Any, List

class FinnhubClient:
    def __init__(self, api_key: str):
        self.api_key = api_key
        self.base_url = "https://finnhub.io/api/v1"

    def get_profile(self, symbol: str) -> Dict[str, Any]:
        res = requests.get(f"{self.base_url}/stock/profile2?symbol={symbol}&token={self.api_key}")
        res.raise_for_status()
        return res.json()

    def get_quote(self, symbol: str) -> Dict[str, Any]:
        res = requests.get(f"{self.base_url}/quote?symbol={symbol}&token={self.api_key}")
        res.raise_for_status()
        return res.json()

    def get_metrics(self, symbol: str) -> Dict[str, Any]:
        res = requests.get(f"{self.base_url}/stock/metric?symbol={symbol}&metric=all&token={self.api_key}")
        res.raise_for_status()
        return res.json()

    def get_financials_reported(self, symbol: str) -> List[Dict[str, Any]]:
        res = requests.get(f"{self.base_url}/stock/financials-reported?symbol={symbol}&freq=annual&token={self.api_key}")
        res.raise_for_status()
        data = res.json()
        return data.get("data", [])

    def extract_key_metrics(self, symbol: str) -> Dict[str, Any]:
        raw_reports = self.get_financials_reported(symbol)

        # Sort by year ascending
        raw_reports.sort(key=lambda x: x["year"])

        history = {
            "revenue": [],
            "net_income": [],
            "operating_cash_flow": [],
            "book_value": [],
            "eps": [],
            "capex": [],
            "da": []
        }

        def get_val(report, section, possible_tags):
            for tag in possible_tags:
                for item in report.get(section, []):
                    if item["concept"] == tag:
                        return float(item["value"])
            return 0.0

        for year_data in raw_reports:
            year = year_data["year"]
            report = year_data["report"]

            rev = get_val(report, "ic", ["us-gaap_Revenues", "us-gaap_SalesRevenueNet", "us-gaap_RevenueFromContractWithCustomerExcludingAssessedTax"])
            ni = get_val(report, "ic", ["us-gaap_NetIncomeLoss"])
            ocf = get_val(report, "cf", ["us-gaap_NetCashProvidedByUsedInOperatingActivities"])
            equity = get_val(report, "bs", ["us-gaap_StockholdersEquity", "us-gaap_StockholdersEquityIncludingPortionAttributableToNoncontrollingInterest"])
            eps = get_val(report, "ic", ["us-gaap_EarningsPerShareDiluted", "us-gaap_EarningsPerShareBasic"])
            capex = get_val(report, "cf", ["us-gaap_PaymentsForPropertyPlantAndEquipment", "us-gaap_PaymentsToAcquirePropertyPlantAndEquipment"])
            da = get_val(report, "cf", ["us-gaap_DepreciationDepletionAndAmortization"])

            history["revenue"].append({"year": year, "value": rev})
            history["net_income"].append({"year": year, "value": ni})
            history["operating_cash_flow"].append({"year": year, "value": ocf})
            history["book_value"].append({"year": year, "value": equity})
            history["eps"].append({"year": year, "value": eps})
            history["capex"].append({"year": year, "value": capex})
            history["da"].append({"year": year, "value": da})

        # Also get current total debt and cash from the latest report
        latest_report = raw_reports[-1]["report"] if raw_reports else {}
        total_debt_short = get_val(latest_report, "bs", ["us-gaap_DebtCurrent", "us-gaap_ShortTermBorrowings"])
        total_debt_long = get_val(latest_report, "bs", ["us-gaap_LongTermDebt", "us-gaap_LongTermDebtNoncurrent"])
        cash = get_val(latest_report, "bs", ["us-gaap_CashAndCashEquivalentsAtCarryingValue"])

        return {
            "history": history,
            "latest_total_debt": total_debt_short + total_debt_long,
            "latest_cash": cash
        }

import google.auth
import google.auth.transport.requests
import requests
import json

def create_firestore_db():
    try:
        credentials, project = google.auth.default(
            scopes=['https://www.googleapis.com/auth/cloud-platform']
        )
        print(f"Using project: {project}")

        # Refresh credential token
        request = google.auth.transport.requests.Request()
        credentials.refresh(request)

        # Endpoint to create default database
        # Base URL: POST https://firestore.googleapis.com/v1/projects/{project_id}/databases?databaseId=(default)
        url = f"https://firestore.googleapis.com/v1/projects/{project}/databases?databaseId=(default)"

        headers = {
            "Authorization": f"Bearer {credentials.token}",
            "Content-Type": "application/json"
        }

        payload = {
            "locationId": "us-central1",
            "type": "FIRESTORE_NATIVE"
        }

        print(f"Sending POST request to create Firestore Native database in location us-central1...")
        response = requests.post(url, headers=headers, json=payload)

        print(f"Status Code: {response.status_code}")
        try:
            res_json = response.json()
            print(json.dumps(res_json, indent=2))
        except Exception:
            print(response.text)

    except Exception as e:
        print(f"Error creating Firestore database: {e}")

if __name__ == "__main__":
    create_firestore_db()

